using HTX586CONTRACT.Domain.Contracts; using Microsoft.EntityFrameworkCore; using Microsoft.EntityFrameworkCore.Metadata.Builders;
namespace HTX586CONTRACT.Infrastructure.Persistence.Configurations;
public sealed class ContractTemplateConfiguration:IEntityTypeConfiguration<ContractTemplate>{public void Configure(EntityTypeBuilder<ContractTemplate>b){b.ToTable("ContractTemplates");b.HasKey(x=>x.Id);b.Property(x=>x.Name).HasMaxLength(200).IsRequired();b.Property(x=>x.HtmlContent).HasColumnType("nvarchar(max)").IsRequired();b.Property(x=>x.CssContent).HasColumnType("nvarchar(max)");b.Property(x=>x.VariablesJson).HasColumnType("nvarchar(max)");b.Property(x=>x.RowVersion).IsRowVersion();b.HasOne(x=>x.ContractType).WithMany(x=>x.Templates).HasForeignKey(x=>x.ContractTypeId).OnDelete(DeleteBehavior.Restrict);b.HasIndex(x=>new{x.ContractTypeId,x.Version}).IsUnique().HasDatabaseName("UX_ContractTemplates_Type_Version");b.HasIndex(x=>new{x.ContractTypeId,x.IsActive,x.EffectiveFrom}).IsDescending(false,false,true).HasDatabaseName("IX_ContractTemplates_Active_EffectiveFrom");b.HasQueryFilter(x=>!x.IsDeleted);}}
